record_types.code:
type Input_t is
   record
      Semantic : library.Semantic := Unknown;
      Source   : Text;
      Offset   : Natural          := 0;
   end record;

type Source is
   record
      Id       : Text;
      array_Id : Text;
      Floats   : access float_Array;
      Texts    : access Text_array;
   end record;
